    test('PSF page handles console status request failure gracefully', async ({ page }) => {
      // This route will make the page think the request failed if it tries again
      // For 'ERR_ABORTED', the focus is more on what the client-side JS does.
      // We can simulate a timeout or a failed response instead for testing error handling.
      await page.route('https://console.python.org/python-dot-org-live-consoles-status', route => {
        // Instead of abort, which Playwright can't directly trigger as client-side,
        // we can simulate a slow response or a network error.
        route.fulfill({ status: 500, contentType: 'application/json', body: JSON.stringify({ error: 'Internal Server Error' }) });
