      await page.goto('https://www.python.org/psf/');

      // Assert that a graceful fallback message is displayed, not a broken UI.
      await expect(page.locator('#console-status-display')).toContainText('Status unavailable');
      // Or assert that there are no visible console errors related to this request
      page.on('console', msg => {
        expect(msg.type()).not.toBe('error');
        expect(msg.text()).not.toContain('Failed to fetch console status');
      });
    });

