    const PERFORMANCE_THRESHOLDS = {
        'https://www.python.org/': {
            maxLoadTimeMs: 1500, // Report: 831ms
            maxResourceCount: 30,  // Report: 22
            maxDomSize: 1000       // Report: 855
        },
        'https://www.python.org/jobs/': {
