            maxResourceCount: 50,  // Report: 41
            maxDomSize: 1000       // Report: 885
        },
        'https://www.python.org/accounts/login/': {
            maxLoadTimeMs: 1000, // Report: 396ms
            maxResourceCount: 40,  // Report: 30
            maxDomSize: 600        // Report: 497
        },
        // Add other critical pages as needed, deriving thresholds from the report or best practices.
    };

    // Helper function to measure page performance metrics
    async function measurePagePerformance(page, url, threshold) {
        const start = Date.now();
        // Navigate and wait until the network is idle, ensuring all resources are likely loaded.
        await page.goto(url, { waitUntil: 'networkidle' });
        const end = Date.now();
        const loadTimeMs = end - start;

        // Get approximate resource count (number of network requests for 'resource' type)
        const requests = await page.evaluate(() => performance.getEntriesByType('resource').length);
        // Get approximate DOM size (total number of elements)
        const domSize = await page.evaluate(() => document.querySelectorAll('*').length);

